import{_ as i,o,c as a,ak as l}from"./chunks/framework.Dpc0wyhY.js";const h=JSON.parse('{"title":"Grid","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/browse/grid.md","filePath":"grindr-api/browse/grid.md"}'),d={name:"grindr-api/browse/grid.md"};function r(c,e,s,t,n,p){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="grid" tabindex="-1">Grid <a class="header-anchor" href="#grid" aria-label="Permalink to “Grid”">​</a></h1><p><a href="#get-cascade">Cascade</a> returns stuff like advertisements, upsells and partial profiles, presumably ranking by algorithms or paid subscriptions. <a href="#search">Search</a> returns full profiles, seemengly ranked simply by distance.</p><h2 id="gridquery" tabindex="-1">GridQuery <a class="header-anchor" href="#gridquery" aria-label="Permalink to “GridQuery”">​</a></h2><ul><li><code>nearbyGeoHash</code> — <a href="/grindr-api/browse/location#geohash">Geohash</a></li><li><code>exploreGeoHash</code> — <a href="/grindr-api/browse/location#geohash">Geohash</a>, optional</li><li><code>photoOnly</code> — boolean, optional</li><li><code>faceOnly</code> — boolean, optional</li><li><code>notRecentlyChatted</code> — boolean, optional</li><li><code>hasAlbum</code> — boolean, optional</li><li><code>fresh</code> — boolean, optional</li><li><code>genders</code> — string, see <a href="/grindr-api/users/profiles#get-genders">Get genders</a>, optional</li><li><code>pageNumber</code> — integer, optional</li></ul><h2 id="cascadequery" tabindex="-1">CascadeQuery <a class="header-anchor" href="#cascadequery" aria-label="Permalink to “CascadeQuery”">​</a></h2><ul><li><em>everything from <a href="#gridquery">GridQuery</a></em></li><li><code>onlineOnly</code> — boolean, optional</li><li><code>ageMin</code> — integer, optional</li><li><code>ageMax</code> — integer, optional</li><li><code>heightCmMin</code> — float, optional</li><li><code>heightCmMax</code> — float, optional</li><li><code>weightGramsMin</code> — float, optional</li><li><code>weightGramsMax</code> — float, optional</li><li><code>tribes</code> — string, see <a href="/grindr-api/users/profiles#tribes">Tribes</a>, optional</li><li><code>lookingFor</code> — string, see <a href="/grindr-api/users/profiles#looking-for">Looking for</a>, optional</li><li><code>relationshipStatuses</code> — string, see <a href="/grindr-api/users/profiles#relationship-status">Relationship status</a>, optional</li><li><code>bodyTypes</code> — string, see <a href="/grindr-api/users/profiles#body-type">Body type</a>, optional</li><li><code>sexualPositions</code> — string, see <a href="/grindr-api/users/profiles#sexual-position-id">Sexual position ID</a>, optional</li><li><code>meetAt</code> — string, see <a href="/grindr-api/users/profiles#meet-at">Meet at</a>, optional</li><li><code>nsfwPics</code> — string, see <a href="/grindr-api/users/profiles#accept-nsfw-pics">Accept NSFW pics</a>, optional</li><li><code>tags</code> — string, see <a href="/grindr-api/users/profiles#profile-tags">Profile tags</a>, optional</li><li><code>rightNow</code> — boolean, optional</li><li><code>favorites</code> — boolean, optional</li><li><code>showSponsoredProfiles</code> — boolean, optional</li><li><code>shuffle</code> — boolean, optional</li><li><code>hot</code> — boolean, optional</li></ul><h2 id="cascaderesponseprofile" tabindex="-1">CascadeResponseProfile <a class="header-anchor" href="#cascaderesponseprofile" aria-label="Permalink to “CascadeResponseProfile”">​</a></h2><ul><li><code>profileId</code> — integer</li><li><code>onlineUntil</code> — unix timestamp in milliseconds</li><li><code>displayName</code> — string</li><li><code>distanceMeters</code> — integer, may be absent</li><li><code>rightNow</code> — <a href="/grindr-api/right-now#rightnowstatus">RightNowStatus</a></li><li><code>unreadCount</code> — integer</li><li><code>isVisiting</code> — boolean</li><li><code>isPopular</code> — boolean</li></ul><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>lastOnline</code> — unix timestamp in milliseconds</li><li><code>photoMediaHashes</code> - array of strings, see <a href="/grindr-api/media/index#media">Media</a></li><li><code>lookingFor</code> — array of integers, see <a href="/grindr-api/users/profiles#looking-for">Looking for</a></li><li><code>sexualPosition</code> — integer, see <a href="/grindr-api/users/profiles#sexual-position-id">Sexual position ID</a>, may be absent</li><li><code>approximateDistance</code> — boolean</li><li><code>isFavorite</code> — boolean</li><li><code>isBoosting</code> — boolean</li><li><code>hasChattedInLast24Hrs</code> — boolean</li><li><code>hasUnviewedSpark</code> — boolean</li><li><code>isTeleporting</code> — boolean</li><li><code>isRoaming</code> — boolean</li><li><code>isRightNow</code> — boolean</li><li><code>hasUnreadThrob</code> — boolean</li><li><code>isBlockable</code> — boolean</li><li><code>isBoostingSomewhereElse</code> — boolean</li></ul><p>Only for <a href="#get-cascade">v4/cascade</a>:</p><ul><li><code>primaryImageUrl</code> — string, URL</li><li><code>favorite</code> — boolean</li><li><code>viewed</code> — boolean</li><li><code>chatted</code> — boolean</li><li><code>roaming</code> — boolean</li></ul><h2 id="cascaderesponse" tabindex="-1">CascadeResponse <a class="header-anchor" href="#cascaderesponse" aria-label="Permalink to “CascadeResponse”">​</a></h2><ul><li><code>items</code> — array of objects <ul><li><code>type</code> — string, see below</li><li><code>data</code> — object, has different field for each <code>type</code>: <ul><li><em><a href="#full-profile-v1"><code>full_profile_v1</code></a></em></li><li><em><a href="#advert-v1"><code>advert_v1</code></a></em></li><li><em><a href="#advert-v1"><code>top_picks_v1</code></a></em></li><li><em><a href="#partial-profile-v1"><code>partial_profile_v1</code></a></em></li><li><em><a href="#explore-aggregation-v1"><code>explore_aggregation_v1</code></a></em></li><li><em><a href="#boost-upsell-v1"><code>boost_upsell_v1</code></a></em></li><li><em><a href="#unlimited-mpu-v1"><code>unlimited_mpu_v1</code></a></em></li><li><em><a href="#xtra-mpu-v1"><code>xtra_mpu_v1</code></a></em></li></ul></li></ul></li><li><code>nextPage</code> — integer</li><li><code>shuffled</code> — boolean</li><li><code>hiddenProfiles</code> — unknown</li><li><code>hiddenProfileInfo</code> — unknown</li></ul><h3 id="partial-profile-v1" tabindex="-1"><code>partial_profile_v1</code> <a class="header-anchor" href="#partial-profile-v1" aria-label="Permalink to “partial_profile_v1”">​</a></h3><ul><li><em>everything from <a href="#cascaderesponseprofile">CascadeResponseProfile</a></em></li><li><code>upsellItemType</code> — string, e.g. <code>&quot;xtra_mpu_v1&quot;</code></li></ul><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, <code>&quot;CascadeItemData$PartialProfileV1&quot;</code></li></ul><h3 id="full-profile-v1" tabindex="-1"><code>full_profile_v1</code> <a class="header-anchor" href="#full-profile-v1" aria-label="Permalink to “full_profile_v1”">​</a></h3><ul><li><em>everything from <a href="#cascaderesponseprofile">CascadeResponseProfile</a></em></li></ul><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><em>everything from <a href="/grindr-api/users/profiles#profilefields">ProfileFields</a></em></li><li><code>@type</code> — string, <code>&quot;CascadeItemData$FullProfileV1&quot;</code></li><li><code>tribes</code> — array of integers, see <a href="/grindr-api/users/profiles#tribes">Tribes</a></li><li><code>socialNetworks</code> — array of <a href="/grindr-api/users/profiles#socialnetwork">SocialNetwork</a></li><li><code>takenOnGrindrMetadata</code> — object <ul><li><em>key is <a href="/grindr-api/media/index#media">Media hash</a></em><ul><li><code>takenOnGrindr</code> — boolean</li><li><code>createdAt</code> — unix timestamp in milliseconds</li></ul></li></ul></li></ul><p>Only for <a href="#get-cascade">v4/cascade</a>:</p><ul><li><code>age</code> — integer</li><li><code>heightCm</code> — integer</li><li><code>weightGrams</code> — integer</li><li><code>bodyType</code> — integer, see <a href="/grindr-api/users/profiles#body-type">Body type</a></li></ul><h3 id="explore-aggregation-v1" tabindex="-1"><code>explore_aggregation_v1</code> <a class="header-anchor" href="#explore-aggregation-v1" aria-label="Permalink to “explore_aggregation_v1”">​</a></h3><ul><li><code>uuid</code> — string, UUIDv4</li><li><code>headerName</code> — string, e.g. <code>🌎 Explore</code></li><li><code>source</code> — string, e.g. <code>cascade</code></li><li><code>items</code> — array of objects: <ul><li><code>@type</code> — string, see below</li><li><em><code>&quot;ExploreAggregationItem$Location&quot;</code> type</em>:</li><li><code>data</code> — object: <ul><li><code>onlineCount</code> — integer</li><li><code>uuid</code> — string, UUIDv3</li><li><code>location</code> — object <ul><li><code>id</code> — integer</li><li><code>name</code> — string, e.g. <code>Minneapolis</code></li><li><code>suffix</code> — string, e.g. <code>🇺🇸</code></li><li><code>lat</code> — float</li><li><code>lon</code> — float</li></ul></li><li><code>profiles</code> — array of objects: <ul><li><code>profileImageUrl</code> — string, URL</li></ul></li></ul></li><li><em><code>&quot;ExploreAggregationItem$Cta&quot;</code> type</em>:</li><li><em>empty</em></li></ul></li></ul><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, always <code>&quot;CascadeItemData$ExploreAggregationV1&quot;</code></li></ul><h3 id="advert-v1" tabindex="-1"><code>advert_v1</code> <a class="header-anchor" href="#advert-v1" aria-label="Permalink to “advert_v1”">​</a></h3><ul><li><code>cascadePlacementName</code> — string, e.g. <code>&quot;mrec-cascade-first&quot;</code></li></ul><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, always <code>&quot;CascadeItemData$Advert&quot;</code></li></ul><h3 id="boost-upsell-v1" tabindex="-1"><code>boost_upsell_v1</code> <a class="header-anchor" href="#boost-upsell-v1" aria-label="Permalink to “boost_upsell_v1”">​</a></h3><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, always <code>&quot;CascadeItemData$BoostUpsellV1&quot;</code></li></ul><p>Empty for <a href="#get-cascade">v4/cascade</a>.</p><h3 id="unlimited-mpu-v1" tabindex="-1"><code>unlimited_mpu_v1</code> <a class="header-anchor" href="#unlimited-mpu-v1" aria-label="Permalink to “unlimited_mpu_v1”">​</a></h3><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, always <code>&quot;CascadeItemData$UnlimitedMpuV1&quot;</code></li></ul><p>Empty for <a href="#get-cascade">v4/cascade</a>.</p><h3 id="xtra-mpu-v1" tabindex="-1"><code>xtra_mpu_v1</code> <a class="header-anchor" href="#xtra-mpu-v1" aria-label="Permalink to “xtra_mpu_v1”">​</a></h3><p>Only for <a href="#get-cascade-legacy">v3/cascade</a>:</p><ul><li><code>@type</code> — string, always <code>&quot;CascadeItemData$XtraMpuV1&quot;</code></li></ul><p>Empty for <a href="#get-cascade">v4/cascade</a>.</p><h2 id="get-cascade" tabindex="-1">Get Cascade <a class="header-anchor" href="#get-cascade" aria-label="Permalink to “Get Cascade”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v4/cascade</span></span></code></pre></div><p>Query:</p><p><a href="#cascadequery">CascadeQuery</a></p><p>Response:</p><p><a href="#cascaderesponse">CascadeResponse</a></p><h2 id="get-cascade-legacy" tabindex="-1">Get Cascade (legacy) <a class="header-anchor" href="#get-cascade-legacy" aria-label="Permalink to “Get Cascade (legacy)”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v3/cascade</span></span></code></pre></div><p>Query:</p><ul><li><em>everything from <a href="#cascadequery">CascadeQuery</a></em></li><li><code>exploreUuid</code> — string, unknown, WIP, optional</li><li><code>sexualHealth</code> — string, see <a href="/grindr-api/users/profiles#sexual-health">Sexual health</a>, optional</li></ul><p>Response:</p><p><a href="#cascaderesponse">CascadeResponse</a></p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to “Search”">​</a></h2><p>Requires <a href="/grindr-api/api-authorization">Authorization</a>.</p><p>Results array appears to be capped to 600 per page. Use <code>searchAfterProfileId</code> or <code>searchAfterDistance</code> for pagination.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /v7/search</span></span></code></pre></div><ul><li><em>everything from <a href="#gridquery">GridQuery</a></em></li><li><code>online</code> — boolean, optional</li><li><code>ageMinimum</code> — integer, optional</li><li><code>ageMaximum</code> — integer, optional</li><li><code>heightMinimum</code> — float, optional</li><li><code>heightMaximum</code> — float, optional</li><li><code>weightMinimum</code> — float, optional</li><li><code>weightMaximum</code> — float, optional</li><li><code>grindrTribesIds</code> — string, see <a href="/grindr-api/users/profiles#tribes">Tribes</a>, optional</li><li><code>lookingForIds</code> — string, see <a href="/grindr-api/users/profiles#looking-for">Looking for</a>, optional</li><li><code>relationshipStatusIds</code> — string, see <a href="/grindr-api/users/profiles#relationship-status">Relationship status</a>, optional</li><li><code>bodyTypeIds</code> — string, see <a href="/grindr-api/users/profiles#body-type">Body type</a>, optional</li><li><code>sexualPositionIds</code> — string, see <a href="#position-id">Sexual position</a>, optional</li><li><code>meetAtIds</code> — string, see <a href="/grindr-api/users/profiles#meet-at">Meet at</a>, optional</li><li><code>nsfwIds</code> — string, see <a href="/grindr-api/users/profiles#accept-nsfw-pics">Accept NSFW pics</a>, optional</li><li><code>profileTags</code> — string, see <a href="/grindr-api/users/profiles#profile-tags">Profile tags</a>, optional</li><li><code>searchAfterDistance</code> — string, optional</li><li><code>searchAfterProfileId</code> — string, optional</li><li><code>freeFilter</code> — boolean, optional</li></ul><p>Response:</p><ul><li><code>profiles</code> — array of objects: <ul><li><code>age</code> — integer or <code>null</code></li><li><code>displayName</code> — string</li><li><code>distance</code> — float</li><li><code>hasFaceRecognition</code> — boolean</li><li><code>isFavorite</code> — boolean</li><li><code>new</code> — boolean</li><li><code>lastChatTimestamp</code> — number</li><li><code>lastViewed</code> — unix timestamp in milliseconds or <code>null</code></li><li><code>lastUpdatedTime</code> — unix timestamp in milliseconds</li><li><code>medias</code> — array of objects or <code>null</code>: <ul><li><code>mediaHash</code> — <a href="/grindr-api/media/index#media">Media hash</a></li><li><code>type</code> — integer, WIP</li><li><code>state</code> — integer, WIP</li></ul></li><li><code>profileId</code> — integer</li><li><code>profileImageMediaHash</code> — <a href="/grindr-api/media/index#media">Media hash</a> or `null</li><li><code>profileTags</code> — array of <a href="/grindr-api/users/profiles#profile-tags">Profile tags</a></li><li><code>seen</code> — unix timestamp in milliseconds</li><li><code>showAge</code> — boolean</li><li><code>showDistance</code> — boolean</li><li><code>approximateDistance</code> — boolean</li><li><code>boosting</code> — boolean</li><li><code>hasAlbum</code> — boolean</li><li><code>gender</code> — array of integers or <code>[-1]</code>, see <a href="/grindr-api/users/profiles#get-genders">Get genders</a></li></ul></li><li><code>lastDistanceInKm</code> — float</li><li><code>lastProfileId</code> — integer</li><li><code>inserts</code> — object: <ul><li><code>mpuFree</code> — integer</li><li><code>mpuXtra</code> — integer</li><li><code>boostUpsell</code> — array of integers</li><li><code>mrecCascadeFirst</code> — integer</li><li><code>mrecCascadeSecond</code> — integer</li><li><code>mrecCascadeThird</code> — integer</li></ul></li></ul>',65)])])}const u=i(d,[["render",r]]);export{h as __pageData,u as default};
